46		var afterTime *time.Time
47		var beforeTime *time.Time
48		if startedAfter != nil && *startedAfter != "" {
49			if parsed, err := time.Parse(time.RFC3339, *startedAfter); err == nil {
50				afterTime = &parsed
51			}
52		}
53		if startedBefore != nil && *startedBefore != "" {
54			if parsed, err := time.Parse(time.RFC3339, *startedBefore); err == nil {
55				beforeTime = &parsed
56			}
57		}
58		sessions := r.State.GetAgentSessionsGraphQL(afterTime, beforeTime)
59		return agentSessionConnectionFrom(sessions, first, after, last, before), nil
60	}
