10		// Track which sessions are expanded
11		let expanded = $state<Set<string>>(new Set());
12		let sessionBodies = $state<Record<string, Pick<SessionNode, 'prompt' | 'response' | 'stderr'>>>(
13			{}
14		);
15	
16		onMount(() => {
17			const timer = window.setInterval(() => {
18				void invalidateAll();
19			}, 2000);
20			return () => window.clearInterval(timer);
21		});
