23		async function toggle(id: string) {
24			const next = new Set(expanded);
25			if (next.has(id)) {
26				next.delete(id);
27			} else {
28				next.add(id);
29				if (!sessionBodies[id]) {
30					const client = createClient(fetch);
31					const detail = await client.request<{ agentSession: SessionNode | null }>(
32						SESSION_DETAIL_QUERY,
33						{ id }
34					);
35					if (detail.agentSession) {
36						sessionBodies = {
37							...sessionBodies,
38							[id]: {
39								prompt: detail.agentSession.prompt,
40								response: detail.agentSession.response,
41								stderr: detail.agentSession.stderr
42							}
43						};
44					}
45				}
46			}
47			expanded = next;
48		}
49	
50		const recordingGap = $derived.by(() => {
51			const sorted = [...data.sessions.edges].sort(
52				(a, b) => new Date(a.node.startedAt).getTime() - new Date(b.node.startedAt).getTime()
53			);
54			for (let i = 1; i < sorted.length; i++) {
55				const prev = new Date(sorted[i - 1].node.startedAt);
56				const next = new Date(sorted[i].node.startedAt);
57				if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
58					return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
59				}
60			}
61			return null;
62		});
63	
64		// Aggregate token summary
65		const summary = $derived.by(() => {
66			let totalPrompt = 0;
67			let totalCompletion = 0;
68			let totalCached = 0;
69			let totalTokens = 0;
70			let paidSessions = 0;
71			let subscriptionSessions = 0;
72			for (const edge of data.sessions.edges) {
73				const s = edge.node;
74				if (s.billingMode === 'paid') paidSessions++;
75				if (s.billingMode === 'subscription') subscriptionSessions++;
76				if (s.tokens) {
77					totalPrompt += s.tokens.prompt ?? 0;
78					totalCompletion += s.tokens.completion ?? 0;
79					totalCached += s.tokens.cached ?? 0;
80					totalTokens += s.tokens.total ?? 0;
81				}
82			}
83			const cacheRate = totalTokens > 0 ? Math.round((totalCached / totalTokens) * 100) : 0;
84			return {
85				totalPrompt,
86				totalCompletion,
87				totalCached,
88				totalTokens,
89				cacheRate,
90				paidSessions,
91				subscriptionSessions
92			};
93		});
