85	// Node is the resolver for the node(id: ID!) field (Relay lookup by global ID).
86	func (r *queryResolver) Node(ctx context.Context, id string) (Node, error) {
87		if strings.HasPrefix(id, "node-") {
88			snap := r.State.GetNodeSnapshot()
89			if snap.ID != id {
90				return nil, nil
91			}
92			return nodeInfoFromSnapshot(snap), nil
93		}
94		if strings.HasPrefix(id, "proj-") {
95			proj, ok := r.State.GetProjectSnapshotByID(id)
96			if !ok {
97				return nil, nil
98			}
99			return proj, nil
100		}
101		return nil, nil
102	}
