142	// GetBeadSnapshot implements ddxgraphql.StateProvider.
143	func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
144		if id == "" {
145			return nil, false
146		}
147	
148		if loc, ok := s.lookupBeadLocation(id); ok {
149			proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
150			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
151				return snap, true
152			}
153			s.forgetBeadLocation(id)
154		}
155	
156		for _, proj := range s.GetProjects() {
157			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
158				s.rememberBeadLocation(id, proj)
159				return snap, true
160			}
161		}
162		return nil, false
163	}
