165	func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry) {
166		if id == "" || proj.ID == "" || proj.Path == "" {
167			return
168		}
169		s.beadIndexMu.Lock()
170		defer s.beadIndexMu.Unlock()
171		if s.beadIndex == nil {
172			s.beadIndex = make(map[string]beadIndexEntry)
173		}
174		s.beadIndex[id] = beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
175	}
