234	func projectEntryToGQL(e ProjectEntry) *ddxgraphql.Project {
235		p := &ddxgraphql.Project{
236			ID:           e.ID,
237			Name:         e.Name,
238			Path:         e.Path,
239			RegisteredAt: e.RegisteredAt.UTC().Format(time.RFC3339),
240			LastSeen:     e.LastSeen.UTC().Format(time.RFC3339),
241		}
242		if e.GitRemote != "" {
243			p.GitRemote = &e.GitRemote
244		}
245		if e.Unreachable {
246			b := true
247			p.Unreachable = &b
248		}
249		if e.TombstonedAt != nil {
250			ts := e.TombstonedAt.UTC().Format(time.RFC3339)
251			p.TombstonedAt = &ts
252		}
253		return p
254	}
