258	// GetWorkersGraphQL implements ddxgraphql.StateProvider.
259	// Reads worker records from disk and returns them as GraphQL Worker values.
260	// If projectID is non-empty, only workers for that project are returned.
261	// An unknown projectID returns an empty list (not an error).
262	//
263	// WorkerRecord stores the project's filesystem path in ProjectRoot, but the
264	// GraphQL argument is a project id (e.g. proj-96d7ea83). Resolve the id to a
265	// path via the project registry before filtering so the two representations
266	// match; previously this compared id→path directly and filtered out every
267	// worker on per-project queries.
268	func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
269		if s.workingDir == "" {
270			return nil
271		}
272		expectedPath := ""
273		if projectID != "" {
274			proj, ok := s.GetProjectByID(projectID)
275			if !ok {
276				return nil
277			}
278			expectedPath = proj.Path
279		}
280		workersDir := filepath.Join(s.workingDir, ".ddx", "workers")
281		entries, err := os.ReadDir(workersDir)
282		if err != nil {
283			return nil
284		}
285		var out []*ddxgraphql.Worker
286		for _, entry := range entries {
287			if !entry.IsDir() {
288				continue
289			}
290			data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
291			if err != nil {
292				continue
293			}
294			var rec WorkerRecord
295			if err := json.Unmarshal(data, &rec); err != nil {
296				continue
297			}
298			if expectedPath != "" && rec.ProjectRoot != expectedPath {
299				continue
300			}
301			out = append(out, workerFromRecord(rec))
302		}
303		// Newest first.
304		sort.Slice(out, func(i, j int) bool {
305			si, sj := out[i].StartedAt, out[j].StartedAt
306			if si == nil || sj == nil {
307				return si != nil
308			}
309			ti, _ := time.Parse(time.RFC3339, *si)
310			tj, _ := time.Parse(time.RFC3339, *sj)
311			return ti.After(tj)
312		})
313		return out
314	}
