395	// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
396	func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
397		attempts := rec.Attempts
398		successes := rec.Successes
399		failures := rec.Failures
400		w := &ddxgraphql.Worker{
401			ID:           rec.ID,
402			Kind:         rec.Kind,
403			State:        rec.State,
404			ProjectRoot:  rec.ProjectRoot,
405			Attempts:     &attempts,
406			Successes:    &successes,
407			Failures:     &failures,
408			RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
409		}
410		if rec.Status != "" {
411			w.Status = &rec.Status
412		}
413		if rec.Harness != "" {
414			w.Harness = &rec.Harness
415		}
416		if rec.Provider != "" {
417			w.Provider = &rec.Provider
418		}
419		if rec.Model != "" {
420			w.Model = &rec.Model
421		}
422		if rec.Effort != "" {
423			w.Effort = &rec.Effort
424		}
425		if rec.Once {
426			b := true
427			w.Once = &b
428		}
429		if rec.PollInterval != "" {
430			w.PollInterval = &rec.PollInterval
431		}
432		if !rec.StartedAt.IsZero() {
433			s := rec.StartedAt.UTC().Format(time.RFC3339)
434			w.StartedAt = &s
435		}
436		if !rec.FinishedAt.IsZero() {
437			s := rec.FinishedAt.UTC().Format(time.RFC3339)
438			w.FinishedAt = &s
439		}
440		if rec.Error != "" {
441			w.Error = &rec.Error
442		}
443		if rec.StdoutPath != "" {
444			w.StdoutPath = &rec.StdoutPath
445		}
446		if rec.SpecPath != "" {
447			w.SpecPath = &rec.SpecPath
448		}
449		if rec.CurrentBead != "" {
450			w.CurrentBead = &rec.CurrentBead
451		}
452		if rec.LastError != "" {
453			w.LastError = &rec.LastError
454		}
455		if rec.LastResult != nil {
456			w.LastResult = workerResultFromRecord(rec.LastResult)
457		}
458		if rec.CurrentAttempt != nil {
459			w.CurrentAttempt = currentAttemptFromRecord(rec.CurrentAttempt)
460		}
461		for _, p := range rec.RecentPhases {
462			pt := p // copy
463			w.RecentPhases = append(w.RecentPhases, &ddxgraphql.PhaseTransition{
464				Phase:    pt.Phase,
465				Ts:       pt.TS.UTC().Format(time.RFC3339),
466				PhaseSeq: pt.PhaseSeq,
467			})
468		}
469		for _, e := range rec.Lifecycle {
470			ev := e
471			gqlEvent := &ddxgraphql.WorkerLifecycleEvent{
472				Action:    ev.Action,
473				Actor:     ev.Actor,
474				Timestamp: ev.Timestamp.UTC().Format(time.RFC3339),
475			}
476			if ev.Detail != "" {
477				gqlEvent.Detail = &ev.Detail
478			}
479			if ev.BeadID != "" {
480				gqlEvent.BeadID = &ev.BeadID
481			}
482			w.LifecycleEvents = append(w.LifecycleEvents, gqlEvent)
483		}
484		if rec.LastAttempt != nil {
485			w.LastAttempt = lastAttemptFromRecord(rec.LastAttempt)
486		}
487		if rec.LandSummary != nil {
488			w.LandSummary = landSummaryFromRecord(rec.LandSummary)
489		}
490		return w
491	}
