493	func workerResultFromRecord(r *WorkerExecutionResult) *ddxgraphql.WorkerExecutionResult {
494		out := &ddxgraphql.WorkerExecutionResult{}
495		if r.BeadID != "" {
496			out.BeadID = &r.BeadID
497		}
498		if r.AttemptID != "" {
499			out.AttemptID = &r.AttemptID
500		}
501		if r.WorkerID != "" {
