676	func (s *ServerState) GetSessionsCostSummaryGraphQL(projectID string, since, until *time.Time) *ddxgraphql.SessionsCostSummary {
677		proj, ok := s.GetProjectByID(projectID)
678		if !ok {
679			return &ddxgraphql.SessionsCostSummary{}
680		}
681		logDir := agent.SessionLogDirForWorkDir(proj.Path)
682		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
683			StartedAfter:  since,
684			StartedBefore: until,
685		})
686		if err != nil {
687			return &ddxgraphql.SessionsCostSummary{}
688		}
689		summary := &ddxgraphql.SessionsCostSummary{}
690		var localTokens int
691		for _, e := range entries {
692			mode := e.BillingMode
693			if mode == "" {
694				mode = agent.BillingModeFor(e.Harness, e.Surface, e.BaseURL)
695			}
696			switch mode {
697			case agent.BillingModePaid:
698				summary.CashUsd += e.CostUSD
699			case agent.BillingModeSubscription:
700				summary.SubscriptionEquivUsd += e.CostUSD
701			case agent.BillingModeLocal:
702				summary.LocalSessionCount++
703				tokens := e.Tokens
704				if tokens == 0 {
705					tokens = e.InputTokens + e.OutputTokens
706				}
707				localTokens += tokens
708			}
709		}
710		if rate := localCostPer1KTokens(proj.Path); rate != nil {
711			estimate := *rate * float64(localTokens) / 1000
712			summary.LocalEstimatedUsd = &estimate
713		}
714		return summary
715	}
