60	interface TokenUsage {
61		prompt: number | null;
62		completion: number | null;
63		total: number | null;
64		cached: number | null;
65	}
66	
67	export interface SessionNode {
68		id: string;
69		projectId: string;
70		beadId: string | null;
71		workerId: string | null;
72		harness: string;
73		model: string;
74		effort: string;
75		status: string;
76		startedAt: string;
77		endedAt: string | null;
78		durationMs: number;
79		cost: number | null;
80		billingMode: 'paid' | 'subscription' | 'local';
81		tokens: TokenUsage | null;
82		outcome: string | null;
83		detail: string | null;
84		prompt?: string | null;
85		response?: string | null;
86		stderr?: string | null;
87	}
