89	interface SessionEdge {
90		node: SessionNode;
91		cursor: string;
92	}
93	
94	interface SessionConnection {
95		edges: SessionEdge[];
96		pageInfo: { hasNextPage: boolean; endCursor: string | null };
97		totalCount: number;
98	}
99	
100	interface SessionsResult {
101		agentSessions: SessionConnection;
102		sessionsCostSummary: SessionsCostSummary;
103	}
