112	export const load: PageLoad = async ({ params, fetch }) => {
113		const client = createClient(fetch as unknown as typeof globalThis.fetch);
114		const data = await client.request<SessionsResult>(SESSIONS_QUERY, {
115			first: 100,
116			projectId: params.projectId
117		});
118		const filteredEdges = data.agentSessions.edges.filter(
119			(e) => e.node.projectId === params.projectId
120		);
121		return {
122			nodeId: params.nodeId,
123			projectId: params.projectId,
124			sessions: {
125				...data.agentSessions,
126				edges: filteredEdges,
127				totalCount: filteredEdges.length
128			},
129			costSummary: data.sessionsCostSummary
130		};
131	};
