97			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
98			const m = Math.floor(ms / 60_000);
99			const s = Math.floor((ms % 60_000) / 1000);
100			return `${m}m ${s}s`;
101		}
