227	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
228		if (typeof input === 'string') {
229			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
230		}
231		if (input instanceof URL) {
232			return input.pathname === '/graphql';
233		}
234		return new URL(input.url).pathname === '/graphql';
235	}
236	
237	async function requestBodyText(
238		input: Parameters<typeof globalThis.fetch>[0],
239		init?: Parameters<typeof globalThis.fetch>[1]
240	): Promise<string | null> {
241		if (typeof init?.body === 'string') {
242			return init.body;
243		}
244		if (input instanceof Request) {
245			return input.clone().text();
246		}
247		return null;
248	}
249	
250	function fallbackGraphQLResponse(data: object): Response {
251		return new Response(JSON.stringify({ data }), {
252			status: 200,
253			headers: { 'content-type': 'application/json' }
254		});
255	}
256	
257	function delegateInputFor(
258		input: Parameters<typeof globalThis.fetch>[0]
259	): Parameters<typeof globalThis.fetch>[0] {
260		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
261			return input;
262		}
263		if (typeof input === 'string' || input instanceof URL) {
264			return '/graphql';
265		}
266		return input;
267	}
268	
269	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
270		const delegate = fetchFn ?? globalThis.fetch;
271		return async (input, init) => {
272			const delegateInput = delegateInputFor(input);
273			const response = await delegate(delegateInput, init);
274			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
275				return response;
276			}
277	
278			const bodyText = await requestBodyText(input, init);
279			if (!bodyText) {
280				return response;
281			}
282	
283			let body: { query?: string };
284			try {
285				body = JSON.parse(bodyText) as { query?: string };
286			} catch {
287				return response;
288			}
289	
290			const data = body.query ? fallbackDataForQuery(body.query) : null;
291			return data ? fallbackGraphQLResponse(data) : response;
292		};
293	}
