295	/**
296	 * Creates a GraphQL HTTP client for queries and mutations.
297	 *
298	 * Pass the SvelteKit-provided `fetch` in load functions so requests
299	 * respect SvelteKit's SSR/CSR fetch instrumentation.
300	 */
301	export function createClient(fetchFn?: typeof globalThis.fetch): GraphQLClient {
302		const url =
303			typeof window !== 'undefined' ? new URL('/graphql', window.location.href).href : '/graphql';
304		return new GraphQLClient(url, { fetch: withStaticPreviewFallback(fetchFn) });
305	}
