83	func ProjectIDForPath(path string) string {
84		canonical, err := filepath.Abs(path)
85		if err == nil {
86			path = canonical
87		}
88		h := sha256.Sum256([]byte(path))
89		return fmt.Sprintf("proj-%x", h[:4])
90	}
